(()=>{'use strict';
const $=s=>document.querySelector(s),T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0;
const F=n=>N(n).toLocaleString('th-TH'),B=n=>N(n).toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2});
const E=s=>T(s).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
let rows=[],source=null,billCache=null,bound=false,dirty=true,ctx={start:'',end:'',ps:''};
function dlabel(s){const p=T(s).split('-');return p.length===3?`${p[2]}/${p[1]}/${p[0]}`:(s||'-')}
function css(){if($('#teleDrawerStyle262'))return;const st=document.createElement('style');st.id='teleDrawerStyle262';st.textContent=`.teleBtn{height:34px;border:1px solid #7c3aed;background:#f5f3ff;color:#5b21b6;border-radius:8px;font-weight:950;padding:0 10px;white-space:nowrap}.teleShade{position:fixed;inset:0;background:#0006;z-index:79;display:none}.teleDrawer{position:fixed;left:0;right:0;bottom:0;height:82vh;background:#fff;z-index:80;border-radius:18px 18px 0 0;box-shadow:0 -12px 40px #0004;transform:translateY(105%);transition:.18s;display:flex;flex-direction:column}.teleDrawer.on{transform:translateY(0)}.teleShade.on{display:block}.teleHead{padding:12px 14px;background:#0b6b31;color:#fff;border-radius:18px 18px 0 0;display:flex;justify-content:space-between;align-items:center;gap:8px}.teleClose{border:1px solid #ffffff66;background:#0001;color:#fff;border-radius:8px;height:34px;padding:0 12px;font-weight:900}.teleBody{padding:10px;overflow:auto}.teleScope{font-size:12px;color:#374151;background:#f8fafc;border:1px solid #e5e7eb;border-radius:10px;padding:8px;margin-bottom:8px}.teleSummary{display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:10px}.teleSummary div{border:1px solid #e5e7eb;background:#f8fafc;border-radius:10px;padding:9px}.teleSummary b{display:block;font-size:12px;color:#374151}.teleSummary strong{font-size:18px}.teleBill{border:1px solid #d1d5db;border-radius:12px;margin-bottom:10px;overflow:hidden;background:#fff}.teleBillHead{background:#f5f3ff;padding:9px 10px;border-bottom:1px solid #ddd6fe}.teleBillHead .store{font-size:15px;font-weight:950;color:#111827}.teleBillHead .meta{font-size:12px;color:#374151;line-height:1.45}.teleTbl{width:100%;border-collapse:collapse;font-size:12px}.teleTbl th,.teleTbl td{border-bottom:1px solid #eef2f7;padding:6px 5px;text-align:center}.teleTbl th{background:#f8fafc}.teleTbl td:nth-child(3),.teleTbl th:nth-child(3){text-align:left}.teleEmpty{padding:18px;text-align:center;color:#6b7280;font-weight:900}@media(max-width:560px){.teleSummary{grid-template-columns:1fr}.teleDrawer{height:86vh}.teleTbl{min-width:720px}.teleBill{overflow:auto}}`;document.head.appendChild(st)}
function ensureUI(){css();const a=document.querySelector('.actions');if(a&&!$('#teleBillsBtn')){const b=document.createElement('button');b.id='teleBillsBtn';b.className='teleBtn';b.type='button';b.textContent='บิล Telesale (0)';b.onclick=open;a.prepend(b)}if(!$('#teleDrawer')){const sh=document.createElement('div');sh.className='teleShade';sh.id='teleShade';sh.onclick=close;const d=document.createElement('div');d.className='teleDrawer';d.id='teleDrawer';d.innerHTML='<div class="teleHead"><b>บิล Telesale: ร้านจริง / ออเดอร์จริง</b><button class="teleClose" id="teleClose" type="button">ปิด</button></div><div class="teleBody" id="teleBody"><div class="teleEmpty">ยังไม่มีข้อมูล Telesale</div></div>';document.body.append(sh,d);$('#teleClose').onclick=close}}
function currentCtx(){return{start:T($('#startDate')?.value),end:T($('#endDate')?.value),ps:T($('#psSelect')?.value)}}
function setContext(next=currentCtx()){const n={start:T(next.start),end:T(next.end),ps:T(next.ps)};if(n.start===ctx.start&&n.end===ctx.end&&n.ps===ctx.ps)return;ctx=n;dirty=true;billCache=null}
function inScope(r){return (r.isTele||T(r.tele))&&(!ctx.start||r.date>=ctx.start)&&(!ctx.end||r.date<=ctx.end)&&(!ctx.ps||r.ps===ctx.ps)}
function buildBills(){setContext();if(billCache&&!dirty)return billCache;const m=new Map();let qty=0,amt=0,count=0;rows.forEach(r=>{if(!inScope(r))return;count++;qty+=N(r.qty);amt+=N(r.amt);const k=[r.inv,r.store,r.tele,r.date].join('|');let b=m.get(k);if(!b){b={inv:T(r.inv)||'-',store:T(r.store)||'ไม่ระบุร้าน',tele:T(r.tele)||'ไม่ระบุเทเลเซลล์',ps:T(r.ps),date:T(r.date),lines:[],qty:0,amt:0};m.set(k,b)}b.lines.push(r);b.qty+=N(r.qty);b.amt+=N(r.amt)});billCache={bills:[...m.values()].sort((a,b)=>(a.date||'').localeCompare(b.date||'')||a.store.localeCompare(b.store,'th')||a.inv.localeCompare(b.inv,'th')),qty,amt,count};dirty=false;return billCache}
function setBtn(){ensureUI();const btn=$('#teleBillsBtn');if(btn)btn.textContent=`บิล Telesale (${F(buildBills().bills.length)})`}
function scopeText(){return`ช่วงวันที่: ${dlabel(ctx.start)} - ${dlabel(ctx.end)} · PS: ${ctx.ps||'ทั้งหมด'}`}
function render(){ensureUI();const body=$('#teleBody');if(!body)return;const data=buildBills(),bs=data.bills;if(!bs.length){body.innerHTML=`<div class="teleScope">${E(scopeText())}</div><div class="teleEmpty">ไม่พบรายการ Telesale ตามวันที่/PS ที่เลือก</div>`;return}body.innerHTML=`<div class="teleScope">${E(scopeText())}</div><div class="teleSummary"><div><b>จำนวนบิล</b><strong>${F(bs.length)}</strong></div><div><b>จำนวนชิ้น</b><strong>${F(data.qty)}</strong></div><div><b>ยอดรวม</b><strong>฿ ${B(data.amt)}</strong></div></div>`+bs.map(b=>`<section class="teleBill"><div class="teleBillHead"><div class="store">ร้าน: ${E(b.store)}</div><div class="meta">เลขบิล/ออเดอร์: <b>${E(b.inv)}</b> · วันที่: ${E(dlabel(b.date))}<br>เทเลเซลล์: ${E(b.tele)}${b.ps?' · PS: '+E(b.ps):''}</div></div><table class="teleTbl"><thead><tr><th>#</th><th>SKU</th><th>สินค้า</th><th>จำนวน</th><th>ราคา</th><th>ยอด</th></tr></thead><tbody>${b.lines.map((r,i)=>`<tr><td>${i+1}</td><td>${E(r.code||'-')}</td><td>${E(r.sku||'')}</td><td>${F(r.qty)}</td><td>${B(r.unit)}</td><td>${B(r.amt)}</td></tr>`).join('')}</tbody></table></section>`).join('')}
function open(){setContext();render();$('#teleShade')?.classList.add('on');$('#teleDrawer')?.classList.add('on')}
function close(){$('#teleShade')?.classList.remove('on');$('#teleDrawer')?.classList.remove('on')}
function loadRows(data,context){ensureUI();if(context)setContext(context);else setContext();if(data===source){setBtn();return}source=data;rows=(data||[]).map(r=>({date:T(r.date),inv:T(r.inv),store:T(r.store)||'ไม่ระบุร้าน',tele:T(r.tele),ps:T(r.ps),isTele:!!r.isTele,code:T(r.code),sku:T(r.sku),qty:N(r.qty),unit:N(r.unit),amt:N(r.amt)}));dirty=true;billCache=null;setBtn();if($('#teleDrawer')?.classList.contains('on'))render()}
function boot(){ensureUI();setBtn();['startDate','endDate','psSelect'].forEach(id=>{const el=$('#'+id);if(el&&!el.dataset.tele262ctx){el.dataset.tele262ctx='1';el.addEventListener('change',()=>{setContext();setBtn();if($('#teleDrawer')?.classList.contains('on'))render()})}});const file=$('#file');if(file&&!file.dataset.tele262Bound){file.dataset.tele262Bound='1';file.addEventListener('change',()=>{source=null;rows=[];dirty=true;billCache=null;setBtn()})}bound=true}
window.DOIT_TELESALE_DRAWER={version:'v262',loadRows,setContext,open,close,render};
if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',boot);else boot();setTimeout(()=>{if(!bound)boot();else ensureUI()},500);
})();